// src/styles/theme.js

export const colors = {
  primary: '#106466', // Verde azulado principal
  primaryLight: '#1A9B9D', // Verde azulado más claro
  primaryDark: '#0A4B4D', // Verde azulado más oscuro
  secondary: '#EE7674', // Rosa salmón (color de acento)
  background: '#F8FAFC', // Gris muy claro para fondos
  white: '#FFFFFF',
  gray100: '#F1F5F9',
  gray200: '#E2E8F0',
  gray300: '#CBD5E1',
  gray400: '#94A3B8',
  error: '#EF4444', // Rojo para errores
  success: '#10B981', // Verde para éxito
  warning: '#F59E0B', // Amarillo para advertencias
  info: '#3B82F6', // Azul para información
};

export const spacing = {
  xs: '4px',
  sm: '8px',
  md: '16px',
  lg: '24px',
  xl: '32px',
  xxl: '48px',
};

export const typography = {
  fontFamily: {
      sans: "'Poppins', sans-serif",
      mono: "'Roboto Mono', monospace",
  },
  fontSize: {
      xs: '12px',
      sm: '14px',
      md: '16px',
      lg: '18px',
      xl: '20px',
      xxl: '24px',
      '3xl': '30px',
      '4xl': '36px',
  },
  fontWeight: {
      light: 300,
      normal: 400,
      medium: 500,
      semiBold: 600,
      bold: 700,
  },
  lineHeight: {
      tight: 1.2,
      normal: 1.5,
      relaxed: 1.75,
  },
};

export const borderRadius = {
  sm: '4px',
  md: '6px', 
  lg: '12px',
  full: '9999px',
};

export const shadows = {
  sm: '0 1px 2px rgba(0, 0, 0, 0.05)',
  md: '0 4px 6px rgba(0, 0, 0, 0.1)',
  lg: '0 10px 15px rgba(0, 0, 0, 0.1)',
  xl: '0 20px 25px rgba(0, 0, 0, 0.15)',
};

// Añadiendo las transiciones que faltan
export const transitions = {
  fast: 'all 0.2s ease',
  medium: 'all 0.3s ease',
  slow: 'all 0.5s ease',
  bounce: 'all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55)',
  elastic: 'all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
};

// Función para aplicar estilos de hover
export const applyHoverStyles = (baseStyles, hoverStyles) => ({
  ...baseStyles,
  transition: transitions.medium,
  ':hover': {
      ...hoverStyles,
  },
});

export default {
  colors,
  spacing,
  typography,
  borderRadius,
  shadows,
  transitions,
  applyHoverStyles,
};
